#!/usr/bin/env node
/**
 * Import AI-generated core questions into the Question table.
 *
 * Source: nclex_core_questions.json (generated by Claude, already has proper
 *         stem/stemZh/optionA-E/explanationZh/optionRationales/usTwDifference)
 *
 * Usage:
 *   node scripts/import-core-questions.js [--file=PATH] [--limit=N] [--truncate-core]
 *
 *   --file=PATH       Path to JSON file. Default: ./nclex_core_questions.json
 *   --limit=N         Import at most N questions (useful for testing).
 *   --truncate-core   Delete all previously imported core questions first.
 *   --dry-run         Parse and validate only, no DB writes.
 */

const { Pool } = require("pg");
const fs = require("fs");
const path = require("path");
const crypto = require("crypto");

// ─── Load env ─────────────────────────────────────────────────────────────────
function loadEnv(file) {
  try {
    const content = fs.readFileSync(file, "utf-8");
    for (const line of content.split("\n")) {
      const t = line.trim();
      if (!t || t.startsWith("#")) continue;
      const eq = t.indexOf("=");
      if (eq === -1) continue;
      const key = t.slice(0, eq).trim();
      let val = t.slice(eq + 1).trim();
      if ((val.startsWith('"') && val.endsWith('"')) || (val.startsWith("'") && val.endsWith("'")))
        val = val.slice(1, -1);
      if (!process.env[key]) process.env[key] = val;
    }
  } catch { /* ignore */ }
}
const ROOT = path.resolve(__dirname, "..");
loadEnv(path.join(ROOT, ".env.local"));
loadEnv(path.join(ROOT, ".env"));

// ─── Args ─────────────────────────────────────────────────────────────────────
function parseArgs(argv) {
  const flags = {};
  for (const a of argv.slice(2)) {
    if (!a.startsWith("--")) continue;
    const [k, v] = a.substring(2).split("=");
    flags[k] = v === undefined ? true : v;
  }
  return flags;
}
const flags = parseArgs(process.argv);
const FILE_PATH    = path.resolve(ROOT, flags["file"] ?? "nclex_core_questions.json");
const LIMIT        = flags["limit"] ? parseInt(flags["limit"]) : Infinity;
const TRUNCATE     = !!flags["truncate-core"];
const DRY_RUN      = !!flags["dry-run"];
const CREATED_BY   = "core-import";

// ─── IRT defaults by difficulty ───────────────────────────────────────────────
const IRT = {
  EASY:   { a: 0.8,  b: -1.0, c: 0.20 },
  MEDIUM: { a: 1.0,  b:  0.0, c: 0.20 },
  HARD:   { a: 1.2,  b:  1.0, c: 0.20 },
};

// ─── Validate + transform ─────────────────────────────────────────────────────
function transform(q, idx) {
  if (!q.stem)         throw new Error("missing stem");
  if (!q.optionA)      throw new Error("missing optionA");
  if (!q.optionB)      throw new Error("missing optionB");
  if (!q.correctAnswer) throw new Error("missing correctAnswer");
  if (!q.questionType) throw new Error("missing questionType");

  const difficulty = ["EASY", "MEDIUM", "HARD"].includes(q.difficulty) ? q.difficulty : "MEDIUM";
  const irt = IRT[difficulty];

  const correctAnswers = Array.isArray(q.correctAnswers) && q.correctAnswers.length
    ? q.correctAnswers
    : q.correctAnswer.split(",").map((s) => s.trim()).filter(Boolean);

  // Validate rationales shape: { A: { en, zh }, ... }
  let rationales = q.optionRationales ?? null;
  if (rationales && typeof rationales === "object") {
    // Already correct shape from generator
  } else {
    rationales = null;
  }

  return {
    id:               crypto.randomUUID(),
    module:           "nclex-rn",
    questionType:     q.questionType === "SATA" ? "SATA" : "MCQ",
    stem:             q.stem.trim(),
    stemZh:           q.stemZh?.trim() ?? null,
    scenarioEn:       null,
    scenarioZh:       null,
    optionA:          q.optionA?.trim() ?? null,
    optionB:          q.optionB?.trim() ?? null,
    optionC:          q.optionC?.trim() ?? null,
    optionD:          q.optionD?.trim() ?? null,
    optionE:          q.optionE?.trim() ?? null,
    optionF:          null,
    correctAnswer:    correctAnswers.join(","),
    correctAnswers,
    explanationZh:    q.explanationZh?.trim() ?? null,
    explanationEn:    null,
    optionRationales: rationales,
    usTwDifference:   q.usTwDifference?.trim() || null,
    domain:           q.domain ?? null,
    subDomain:        null,
    tags:             [],
    cjmmStep:         null,
    bloomsLevel:      null,
    caseStudySetId:   null,
    caseStudyPosition: null,
    irtA:             irt.a,
    irtB:             irt.b,
    irtC:             irt.c,
    difficulty,
    status:           "APPROVED",
    createdBy:        CREATED_BY,
  };
}

// ─── Main ─────────────────────────────────────────────────────────────────────
async function main() {
  if (!fs.existsSync(FILE_PATH)) {
    console.error(`❌  File not found: ${FILE_PATH}`);
    process.exit(1);
  }

  console.log(`📂  Reading ${FILE_PATH} ...`);
  const raw = fs.readFileSync(FILE_PATH, "utf-8");
  console.log(`    File size: ${(raw.length / 1024 / 1024).toFixed(1)} MB`);

  let data;
  try {
    data = JSON.parse(raw);
  } catch (e) {
    console.error("❌  JSON parse failed:", e.message);
    process.exit(1);
  }

  if (!Array.isArray(data)) {
    console.error("❌  Expected a JSON array at top level.");
    process.exit(1);
  }

  const items = LIMIT < Infinity ? data.slice(0, LIMIT) : data;
  console.log(`\n📊  Questions in file: ${data.length}`);
  if (LIMIT < Infinity) console.log(`    Processing first: ${items.length}`);

  // Validate all rows
  let validCount = 0;
  let skipCount = 0;
  const transformed = [];
  for (let i = 0; i < items.length; i++) {
    try {
      transformed.push(transform(items[i], i));
      validCount++;
    } catch (err) {
      skipCount++;
      if (skipCount <= 5) console.warn(`  ⚠️  Row ${i}: ${err.message}`);
    }
  }
  console.log(`    Valid: ${validCount}  |  Skipped: ${skipCount}`);

  // Domain breakdown
  const byDomain = {};
  for (const q of transformed) {
    byDomain[q.domain ?? "(none)"] = (byDomain[q.domain ?? "(none)"] ?? 0) + 1;
  }
  console.log("\n  Domain breakdown:");
  for (const [d, n] of Object.entries(byDomain).sort((a, b) => b[1] - a[1])) {
    console.log(`    ${d}: ${n}`);
  }

  if (DRY_RUN) {
    console.log("\n✅  Dry-run complete — no DB changes.");
    return;
  }

  if (!process.env.DATABASE_URL) {
    console.error("\n❌  DATABASE_URL is not set.");
    process.exit(1);
  }

  const pool = new Pool({ connectionString: process.env.DATABASE_URL, max: 4 });
  const client = await pool.connect();

  try {
    if (TRUNCATE) {
      console.log('\n🗑️   Removing previous core-import questions...');
      const del = await client.query('DELETE FROM "Question" WHERE "createdBy" = $1', [CREATED_BY]);
      console.log(`    Deleted ${del.rowCount} rows.`);
    } else {
      const existing = await client.query(
        'SELECT COUNT(*)::int AS n FROM "Question" WHERE "createdBy" = $1',
        [CREATED_BY]
      );
      const n = existing.rows[0].n;
      if (n > 0) {
        console.log(`\n⚠️   Found ${n} existing core-import questions.`);
        console.log(`    Use --truncate-core to replace them, or --limit to add a subset.`);
        console.log(`    Proceeding to INSERT (duplicates will error — use --truncate-core to avoid).\n`);
      }
    }

    const colList = [
      "id", "module", "questionType",
      "stem", "stemZh", "scenarioEn", "scenarioZh",
      "optionA", "optionB", "optionC", "optionD", "optionE", "optionF",
      "correctAnswer", "correctAnswers",
      "explanationZh", "explanationEn",
      "optionRationales", "usTwDifference",
      "domain", "subDomain", "tags",
      "cjmmStep", "bloomsLevel", "caseStudySetId", "caseStudyPosition",
      "irtA", "irtB", "irtC", "difficulty", "status", "createdBy", "updatedAt",
    ];
    const quotedCols = colList.map((c) => `"${c}"`).join(", ");

    const BATCH = 100;
    let inserted = 0;
    let errors = 0;
    const startTime = Date.now();

    for (let i = 0; i < transformed.length; i += BATCH) {
      const slice = transformed.slice(i, i + BATCH);
      const values = [];
      const placeholders = [];
      const now = new Date().toISOString();

      slice.forEach((q, idx) => {
        const row = [
          q.id, q.module, q.questionType,
          q.stem, q.stemZh, q.scenarioEn, q.scenarioZh,
          q.optionA, q.optionB, q.optionC, q.optionD, q.optionE, q.optionF,
          q.correctAnswer, q.correctAnswers,
          q.explanationZh, q.explanationEn,
          q.optionRationales ? JSON.stringify(q.optionRationales) : null,
          q.usTwDifference,
          q.domain, q.subDomain, q.tags,
          q.cjmmStep, q.bloomsLevel, q.caseStudySetId, q.caseStudyPosition,
          q.irtA, q.irtB, q.irtC, q.difficulty, q.status, q.createdBy, now,
        ];
        const base = idx * colList.length;
        placeholders.push("(" + colList.map((_, k) => `$${base + k + 1}`).join(", ") + ")");
        values.push(...row);
      });

      try {
        await client.query(
          `INSERT INTO "Question" (${quotedCols}) VALUES ${placeholders.join(", ")}`,
          values
        );
        inserted += slice.length;
      } catch (err) {
        errors += slice.length;
        console.error(`\n  ✗ Batch ${i}-${i + BATCH} failed: ${err.message.slice(0, 120)}`);
      }

      const pct = Math.round((i + BATCH) / transformed.length * 100);
      const elapsed = ((Date.now() - startTime) / 1000).toFixed(0);
      process.stdout.write(`\r  [${Math.min(pct, 100)}%] ${inserted} inserted  ${errors} errors  ${elapsed}s`);
    }

    const elapsed = ((Date.now() - startTime) / 1000).toFixed(1);
    console.log(`\n\n✅  Done in ${elapsed}s`);
    console.log(`   Inserted: ${inserted}  |  Errors: ${errors}`);

    // Final distribution
    const dist = await client.query(
      `SELECT "domain", COUNT(*)::int AS n FROM "Question"
       WHERE "createdBy" = $1 GROUP BY "domain" ORDER BY n DESC`,
      [CREATED_BY]
    );
    console.log("\n  Imported distribution:");
    for (const r of dist.rows) console.log(`    ${r.domain ?? "(none)"}: ${r.n}`);

    // Total APPROVED
    const total = await client.query(
      `SELECT COUNT(*)::int AS n FROM "Question" WHERE status = 'APPROVED'`
    );
    console.log(`\n  Total APPROVED questions in DB: ${total.rows[0].n}`);

  } finally {
    client.release();
    await pool.end();
  }
}

main().catch((err) => {
  console.error("Fatal:", err);
  process.exit(1);
});
